const fs = require('fs');

// Load coupons from file
function loadCoupons() {
  const rawData = fs.readFileSync('coupons.json');
  return JSON.parse(rawData);
}

// Save coupons to file
function saveCoupons(coupons) {
  const data = JSON.stringify(coupons, null, 2);
  fs.writeFileSync('coupons.json', data);
}

// Check if coupon is valid (not expired and not used)
function isValidCoupon(coupon) {
  return !coupon.expired && !coupon.used;
}

// Apply discount to total price
function applyDiscount(total, discount) {
  return total - (total * discount);
}

// Redeem coupon
function redeemCoupon(code) {
  const coupons = loadCoupons();
  const coupon = coupons.find(c => c.code === code);

  if (!coupon || !isValidCoupon(coupon)) {
    return { error: 'Invalid or expired coupon.' };
  }

  coupon.used = true;
  saveCoupons(coupons);

  return { discount: coupon.discount, total: applyDiscount(totalPrice, coupon.discount) };
}

